outer.addEventListener('click', () => console.log('outer (bubble)'));
inner.addEventListener('click', () => console.log('inner (target)'));
outer.addEventListener('click', () => console.log('outer (capture)'), true);

// Clicking #inner logs:
//   'outer (capture)'  -> capturing phase, top-down
//   'inner (target)'
//   'outer (bubble)'   -> bubbling phase, bottom-up

const list = document.querySelector("#todo-list");

// ONE listener handles clicks from any <li>, current or future
list.addEventListener("click", (e) => {
  const item = e.target.closest("li");   // works even if a child was clicked
  if (!item || !list.contains(item)) return;
  console.log("clicked item:", item.dataset.id);
});

// Adding items later needs NO new listeners:
list.insertAdjacentHTML("beforeend", '<li data-id="99">New</li>');

// target = what was clicked; currentTarget = the <ul> the listener is on

console.log(typeof globalThis);          // "object" — exists everywhere

// feature-detect without env-specific names
console.log(typeof globalThis.setTimeout); // "function"

// define something globally (use sparingly)
globalThis.APP_VERSION = "1.0.0";
console.log(globalThis.APP_VERSION);       // "1.0.0"

// in a browser globalThis === window; in a worker === self; in Node === global
console.log("unified global reference ✓");

const outer = "global";
function makeGreeter() {
  const greeting = "Hi";            // makeGreeter scope
  return function () {
    const who = "there";            // inner scope
    return greeting + " " + who + " (" + outer + ")"; // walks the chain
  };
}
console.log(makeGreeter()());       // "Hi there (global)"

// Outer scope cannot see an inner variable
function f() { let secret = 42; return secret; }
console.log(f());                    // 42
try {
  console.log(secret);               // not visible out here
} catch (e) {
  console.log(e.name);               // "ReferenceError"
}

console.log(0 && "x");      // 0      (&&: first falsy)
console.log("a" && "b");    // "b"    (&&: last, all truthy)
console.log("" || "fb");    // "fb"   (||: first truthy)
console.log("a" || "b");    // "a"

// guard: run only when truthy (RHS skipped otherwise)
let calls = 0;
const run = () => { calls++; return "ran"; };
false && run();
console.log("skipped, calls =", calls); // 0
true && run();
console.log("executed, calls =", calls); // 1

// default value
const name = "";
console.log(name || "Guest"); // "Guest"

const obj = { a: 1 };
console.log(Reflect.get(obj, "a"));   // 1
Reflect.set(obj, "b", 2);
console.log(Reflect.has(obj, "b"));   // true
console.log(Reflect.ownKeys({ x: 1, y: 2 })); // ["x", "y"]

// pairs with Proxy: forward the default behaviour with Reflect
const logged = new Proxy(obj, {
  get(target, key, recv) {
    console.log("read:", key);
    return Reflect.get(target, key, recv); // default get
  },
});
console.log(logged.a);                 // logs "read: a" → 1

// ── ES Modules (the standard) ──
export const add = (a, b) => a + b;
export default function multiply(a, b) { return a * b; }
import multiply, { add } from "./math.js";

// ── CommonJS (Node legacy) ──
const add2 = (a, b) => a + b;
module.exports = { add: add2 };
module.exports.multiply = (a, b) => a * b;
const { add: addCjs } = require("./math.js");

// ESM resolves imports statically (tree-shakeable, supports top-level await);
// CJS require() is a synchronous function call resolved at runtime.

const arr = [1, 2];
arr.push(3);                 // allowed — const locks the binding, not contents
console.log(arr);             // [1, 2, 3]

const frozen = Object.freeze({ a: 1, nested: { b: 2 } });
frozen.a = 99;                // ignored (throws in strict mode)
frozen.c = 3;                 // ignored
console.log(frozen);          // { a: 1, nested: { b: 2 } }
console.log(Object.isFrozen(frozen)); // true

// freeze is SHALLOW — nested objects stay mutable
frozen.nested.b = 999;
console.log(frozen.nested.b); // 999  ⚠️

const a = Object.preventExtensions({ x: 1 });
a.x = 2; a.y = 3;            // edit ok, add ignored
console.log(a);              // { x: 2 }

const b = Object.seal({ x: 1 });
b.x = 9; delete b.x; b.y = 3; // edit ok; delete + add ignored
console.log(b);              // { x: 9 }

const c = Object.freeze({ x: 1 });
c.x = 9; c.y = 3;            // everything ignored
console.log(c);              // { x: 1 }

console.log(Object.isSealed(b), Object.isFrozen(c)); // true true

// regular functions have their own 'arguments'; arrows don't
function regular() { return arguments.length; }
console.log(regular(1, 2, 3));      // 3
const arrow = (...args) => args.length;  // arrows use rest instead
console.log(arrow(1, 2, 3));        // 3

// arrows can't construct and have no prototype
const Arrow = () => {};
console.log(Arrow.prototype);       // undefined
try { new Arrow(); } catch (e) { console.log(e.name); } // "TypeError"

// 'this': a regular method binds to its object
const obj = { v: 42, get() { return this.v; } };
console.log(obj.get());             // 42

// CSR: the server sends an almost-empty shell…
//   <body><div id="root"></div><script src="/app.js"></script></body>
// …and the browser builds the UI:
const root = document.getElementById("root");
root.innerHTML = renderApp(); // React/Vue mount here on the client

