// localStorage — persists across sessions (strings only)
localStorage.setItem("theme", "dark");
console.log(localStorage.getItem("theme"));     // "dark"
localStorage.setItem("user", JSON.stringify({ id: 1 })); // objects → JSON

// sessionStorage — same API, gone when the tab closes
sessionStorage.setItem("wizardStep", "2");

// cookie — small, sent with every request; secure it with flags
document.cookie = "token=abc; Max-Age=3600; Secure; SameSite=Lax";
// (HttpOnly cookies are set by the SERVER and are invisible to JS)

// preventDefault — stop the page reload, handle the form yourself
form.addEventListener("submit", (e) => {
  e.preventDefault();          // browser won't navigate/reload
  submitViaFetch(new FormData(form));
});

// stopPropagation — keep the button click from reaching the card handler
card.addEventListener("click", () => console.log("card clicked"));
buttonInsideCard.addEventListener("click", (e) => {
  e.stopPropagation();         // "card clicked" will NOT log
  console.log("button only");
  // e.stopImmediatePropagation() would also block other listeners here
});

// They're independent: preventDefault does NOT stop bubbling, and vice versa.

console.log("1: sync start");

setTimeout(() => console.log("4: async timer callback"), 0);
Promise.resolve().then(() => console.log("3: async microtask"));

// A blocking synchronous loop — the thread is busy here
let total = 0;
for (let i = 0; i < 1_000_000; i++) total += i;
console.log("2: sync done, total =", total);

// Order: 1, 2, 3, 4 — sync finishes fully before any async callback runs

console.log('1');
setTimeout(() => console.log('5 macrotask'), 0);
Promise.resolve()
  .then(() => console.log('3 microtask'))
  .then(() => console.log('4 microtask'));
console.log('2');
// 1, 2, 3, 4, 5

const person = { name: "Sam" };
function intro(greeting, punct) { return greeting + ", " + this.name + punct; }

console.log(intro.call(person, "Hi", "!"));      // call: comma args → "Hi, Sam!"
console.log(intro.apply(person, ["Hey", "."]));  // apply: array args → "Hey, Sam."

const sayHello = intro.bind(person, "Hello");    // bind: preset this + first arg
console.log(sayHello("?"));                       // "Hello, Sam?"

// Borrow a method onto an array-like value
function sum() {
  return Array.prototype.reduce.call(arguments, (a, b) => a + b, 0);
}
console.log(sum(1, 2, 3, 4));                      // 10

// let/const live in the TDZ until their declaration line
try {
  console.log(x);     // access during the TDZ
  let x = 1;
} catch (e) {
  console.log(e.name); // "ReferenceError"
}

// var is hoisted AND initialised → no TDZ, just undefined
console.log(typeof y); // "undefined" (no throw)
var y = 2;

// after the declaration, the binding is fully usable
let z = 10;
console.log(z);        // 10

console.log(0.1 + 0.2);            // 0.30000000000000004
console.log(0.1 + 0.2 === 0.3);    // false

// 1) tolerance comparison
const eq = (a, b) => Math.abs(a - b) < Number.EPSILON;
console.log(eq(0.1 + 0.2, 0.3));   // true

// 2) round for display
console.log((0.1 + 0.2).toFixed(2)); // "0.30"

// 3) work in integer minor units (e.g. cents)
console.log((10 + 20) / 100);       // 0.3 exactly

// WRONG — a brand-new function each time, so removal does nothing
el.addEventListener("click", () => doThing());
el.removeEventListener("click", () => doThing());  // no-op: different reference

// RIGHT — keep ONE reference and reuse it
const handler = () => doThing();
el.addEventListener("click", handler);
el.removeEventListener("click", handler);          // removed ✓

// .bind() also returns a NEW function — store it if you must remove it
const bound = obj.method.bind(obj);
el.addEventListener("click", bound);
el.removeEventListener("click", bound);

// modern alternatives
el.addEventListener("click", onceFn, { once: true });   // auto-removes
const ctrl = new AbortController();
el.addEventListener("click", a, { signal: ctrl.signal });
el.addEventListener("scroll", b, { signal: ctrl.signal });
ctrl.abort();                                           // removes BOTH
